import React from 'react';
import { Button, Layout, Menu, Space, Typography } from 'antd';
import { BrowserRouter, Routes, Route, Link, Navigate } from 'react-router-dom';
import Home from './components/Home';
import Dashboard from './components/Dashboard';
import About from './components/About';
import Register from './components/Register';
import Login from './components/Login';
import ArticleDetail from './components/ArticleDetail';
import { clearAuthSession, loadAuthSession, onAuthChanged } from './common/auth';

const { Header, Content, Footer } = Layout;
const { Title, Text } = Typography;

const navItems = [
  { key: 'home', label: <Link to="/">Home</Link> },
  { key: 'dashboard', label: <Link to="/dashboard">Dashboard</Link> },
  { key: 'about', label: <Link to="/about">About</Link> },
  { key: 'register', label: <Link to="/register">Register</Link> },
  { key: 'login', label: <Link to="/login">Login</Link> },
];

const App = () => {
  const [session, setSession] = React.useState(loadAuthSession());

  React.useEffect(() => onAuthChanged(() => setSession(loadAuthSession())), []);

  const handleLogout = () => {
    clearAuthSession();
    setSession(null);
  };

  return (
    <BrowserRouter>
      <Layout className="app-shell">
        <Header className="app-header">
          <div className="brand-block">
            <Title level={3} className="brand-title">Blog SPA</Title>
            <Text className="brand-subtitle">Lab 9 · React + API + Basic Auth</Text>
          </div>
          <Menu theme="dark" mode="horizontal" items={navItems} selectable={false} className="nav-menu" />
          <Space className="auth-block">
            <Text className="auth-status">
              {session ? `Signed in as ${session.username}` : 'Not signed in'}
            </Text>
            {session ? (
              <Button onClick={handleLogout}>Logout</Button>
            ) : null}
          </Space>
        </Header>

        <Content className="app-content">
          <Routes>
            <Route path="/" element={<Home />} />
            <Route path="/dashboard" element={<Dashboard />} />
            <Route path="/about" element={<About />} />
            <Route path="/register" element={<Register />} />
            <Route path="/login" element={<Login />} />
            <Route path="/a/:aid" element={<ArticleDetail />} />
            <Route path="*" element={<Navigate to="/" replace />} />
          </Routes>
        </Content>

        <Footer className="app-footer">
          <Space direction="vertical" size={0}>
            <Text strong>VT6003CEM Demo SPA</Text>
            <Text type="secondary">Connected to the Koa API for Lab 9</Text>
          </Space>
        </Footer>
      </Layout>
    </BrowserRouter>
  );
};

export default App;

export type ApiArticle = Record<string, unknown>;

const firstString = (article: ApiArticle, keys: string[]) => {
  for (const key of keys) {
    const value = article[key];
    if (typeof value === 'string' && value.trim()) {
      return value;
    }
    if (typeof value === 'number') {
      return String(value);
    }
  }

  return '';
};

export type NormalizedArticle = {
  id: string;
  title: string;
  body: string;
  image?: string;
  raw: ApiArticle;
};

export const normalizeArticle = (article: ApiArticle): NormalizedArticle => {
  const idValue = article.id ?? article.ID ?? article.articleId ?? article.article_id ?? '';
  const id = typeof idValue === 'number' ? String(idValue) : String(idValue);
  const title = firstString(article, ['title', 'name', 'headline', 'subject']) || `Article ${id || '?'}`;
  const body = firstString(article, ['fullText', 'fulltext', 'content', 'body', 'description', 'articleText', 'text']) || 'No article content available.';
  const image = firstString(article, ['image', 'imageURL', 'imageUrl', 'cover', 'thumbnail']) || undefined;

  return {
    id,
    title,
    body,
    image,
    raw: article,
  };
};

export type ApiArticle = Record<string, unknown>;

const firstString = (article: ApiArticle, keys: string[]) => {
  for (const key of keys) {
    const value = article[key];
    if (typeof value === 'string' && value.trim()) {
      return value;
    }
    if (typeof value === 'number') {
      return String(value);
    }
  }

  return '';
};

export type NormalizedArticle = {
  id: string;
  title: string;
  body: string;
  image?: string;
  raw: ApiArticle;
};

export const normalizeArticle = (article: ApiArticle): NormalizedArticle => {
  const idValue = article.id ?? article.ID ?? article.articleId ?? article.article_id ?? '';
  const id = typeof idValue === 'number' ? String(idValue) : String(idValue);
  const title = firstString(article, ['title', 'name', 'headline', 'subject']) || `Article ${id || '?'}`;
  const body =
    firstString(article, [
      'fullText',
      'fulltext',
      'full_text',
      'allText',
      'alltext',
      'all_text',
      'content',
      'body',
      'description',
      'articleText',
      'article_text',
      'text',
    ]) || 'No article content available.';
  const image = firstString(article, ['image', 'imageURL', 'imageUrl', 'cover', 'thumbnail']) || undefined;

  return {
    id,
    title,
    body,
    image,
    raw: article,
  };
};

export type AuthSession = {
  username: string;
  token: string;
};

const AUTH_STORAGE_KEY = 'lab04.auth.session';
const AUTH_CHANGED_EVENT = 'lab04-auth-changed';

const emitAuthChanged = () => {
  if (typeof window !== 'undefined') {
    window.dispatchEvent(new Event(AUTH_CHANGED_EVENT));
  }
};

const toBase64 = (value: string) => {
  const bytes = new TextEncoder().encode(value);
  let binary = '';

  bytes.forEach((byte) => {
    binary += String.fromCharCode(byte);
  });

  return btoa(binary);
};

export const buildBasicAuthHeader = (username: string, password: string) => `Basic ${toBase64(`${username}:${password}`)}`;

export const saveAuthSession = (session: AuthSession) => {
  localStorage.setItem(AUTH_STORAGE_KEY, JSON.stringify(session));
  emitAuthChanged();
};

export const loadAuthSession = (): AuthSession | null => {
  const raw = localStorage.getItem(AUTH_STORAGE_KEY);

  if (!raw) {
    return null;
  }

  try {
    return JSON.parse(raw) as AuthSession;
  } catch {
    return null;
  }
};

export const clearAuthSession = () => {
  localStorage.removeItem(AUTH_STORAGE_KEY);
  emitAuthChanged();
};

export const getAuthHeaders = () => {
  const session = loadAuthSession();

  if (!session) {
    return {};
  }

  return {
    Authorization: `Basic ${session.token}`,
  };
};

export const onAuthChanged = (handler: () => void) => {
  window.addEventListener(AUTH_CHANGED_EVENT, handler);
  window.addEventListener('storage', handler);

  return () => {
    window.removeEventListener(AUTH_CHANGED_EVENT, handler);
    window.removeEventListener('storage', handler);
  };
};

import axios from 'axios';
import { api } from './http-common';

export const http = axios.create({
  baseURL: api.uri,
});

export const api = {
