import React from 'react';
import { Card, Typography } from 'antd';

const { Paragraph, Title } = Typography;

const About = () => (
  <Card className="page-card" title="About this SPA">
    <Title level={2}>React learning page</Title>
    <Paragraph>
      This page demonstrates routing, reusable components, props, state, and simple Ant Design layout.
    </Paragraph>
    <Paragraph>
      It matches the Lab 8 requirement for placeholder pages and SPA navigation.
    </Paragraph>
  </Card>
);

export default About;

import React from 'react';
import axios from 'axios';
import { Alert, Button, Card, Empty, Spin, Typography } from 'antd';
import { RollbackOutlined } from '@ant-design/icons';
import { useNavigate, useParams } from 'react-router-dom';
import { api } from '../common/http-common';
import { normalizeArticle, type NormalizedArticle } from '../common/article';

const { Paragraph, Title, Text } = Typography;

const ArticleDetail = () => {
  const { aid } = useParams();
  const navigate = useNavigate();
  const [article, setArticle] = React.useState<NormalizedArticle | null>(null);
  const [loading, setLoading] = React.useState(true);
  const [error, setError] = React.useState<string | null>(null);

  React.useEffect(() => {
    let active = true;

    const loadArticle = async () => {
      if (!aid) {
        setLoading(false);
        setError('Missing article identifier');
        return;
      }

      try {
        setLoading(true);
        setError(null);
        const response = await axios.get(`${api.uri}/articles/${aid}`);

        if (active) {
          setArticle(normalizeArticle(response.data as Record<string, unknown>));
        }
      } catch (err) {
        if (active) {
          const message = axios.isAxiosError(err)
            ? err.response?.data?.error ?? err.response?.data?.message ?? err.message
            : 'Unable to load article';
          setError(message);
          setArticle(null);
        }
      } finally {
        if (active) {
          setLoading(false);
        }
      }
    };

    loadArticle();

    return () => {
      active = false;
    };
  }, [aid]);

  if (loading) {
    return <Spin size="large" tip="Loading article details..." />;
  }

  if (error) {
    return <Alert className="page-card" type="error" showIcon message="Unable to load article" description={error} />;
  }

  if (!article) {
    return (
      <Card className="page-card">
        <Empty description="Article not found" />
        <div className="detail-actions">
          <Button icon={<RollbackOutlined />} onClick={() => navigate(-1)}>
            Go back
          </Button>
        </div>
      </Card>
    );
  }

  return (
    <Card
      className="page-card"
      cover={article.image ? <img alt={article.title} src={article.image} style={{ maxHeight: 320, objectFit: 'cover' }} /> : null}
    >
      <Title level={2}>{article.title}</Title>
      <Paragraph>{article.body}</Paragraph>
      <Text type="secondary">Article ID: {article.id}</Text>
      <div className="detail-actions">
        <Button type="primary" icon={<RollbackOutlined />} onClick={() => navigate(-1)}>
          Back
        </Button>
      </div>
    </Card>
  );
};

export default ArticleDetail;

import React from 'react';
import axios from 'axios';
import { Alert, Card, Col, Row, Spin, Tag, Typography } from 'antd';
import { Link } from 'react-router-dom';
import { api } from '../common/http-common';
import { normalizeArticle, type NormalizedArticle } from '../common/article';

const { Paragraph, Title } = Typography;

const Articles = () => {
  const [articles, setArticles] = React.useState<NormalizedArticle[]>([]);
  const [loading, setLoading] = React.useState(true);
  const [error, setError] = React.useState<string | null>(null);

  React.useEffect(() => {
    let active = true;

    const loadArticles = async () => {
      try {
        setLoading(true);
        setError(null);

        const response = await axios.get(`${api.uri}/articles`);
        const data = Array.isArray(response.data) ? response.data : [];

        if (active) {
          setArticles(data.map((item) => normalizeArticle(item as Record<string, unknown>)));
        }
      } catch (err) {
        if (active) {
          const message = axios.isAxiosError(err)
            ? err.response?.data?.error ?? err.response?.data?.message ?? err.message
            : 'Unable to load articles';
          setError(message);
          setArticles([]);
        }
      } finally {
        if (active) {
          setLoading(false);
        }
      }
    };

    loadArticles();

    return () => {
      active = false;
    };
  }, []);

  if (loading) {
    return <Spin size="large" tip="Loading articles from the API..." />;
  }

  if (error) {
    return <Alert className="page-card" type="error" showIcon message="Unable to load articles" description={error} />;
  }

  if (!articles.length) {
    return <div>There is no article available now.</div>;
  }

  return (
    <div className="article-grid">
      <Title level={2}>Latest Articles</Title>
      <Row gutter={[16, 16]} justify="space-around">
        {articles.map((article) => (
          <Col xs={24} sm={12} lg={8} key={article.id}>
            <Card
              className="article-card"
              cover={article.image ? <img alt={article.title} src={article.image} style={{ height: 180, objectFit: 'cover' }} /> : null}
              title={article.title}
              extra={<Tag color="blue">#{article.id}</Tag>}
            >
              <Paragraph>{article.body}</Paragraph>
              <Link to={`/a/${article.id}`}>Details</Link>
            </Card>
          </Col>
        ))}
      </Row>
    </div>
  );
};

export default Articles;

import React from 'react';
import axios from 'axios';
import { Alert, Card, Col, Row, Spin, Tag, Typography } from 'antd';
import { Link } from 'react-router-dom';
import { api } from '../common/http-common';
import { normalizeArticle, type NormalizedArticle } from '../common/article';
import fallbackArticles from '../data/articles.json';

const { Paragraph, Title } = Typography;

const Articles = () => {
  const [articles, setArticles] = React.useState<NormalizedArticle[]>([]);
  const [loading, setLoading] = React.useState(true);
  const [error, setError] = React.useState<string | null>(null);

  const loadFallbackArticles = () => {
    const data = Array.isArray(fallbackArticles) ? fallbackArticles : [];
    setArticles(data.map((item) => normalizeArticle(item as Record<string, unknown>)));
  };

  React.useEffect(() => {
    let active = true;

    const loadArticles = async () => {
      try {
        setLoading(true);
        setError(null);

        const response = await axios.get(`${api.uri}/articles`);
        const data = Array.isArray(response.data) ? response.data : [];

        if (active) {
          if (data.length) {
            setArticles(data.map((item) => normalizeArticle(item as Record<string, unknown>)));
          } else {
            loadFallbackArticles();
          }
        }
      } catch (err) {
        if (active) {
          console.warn('API articles request failed, using sample articles instead.', err);
          loadFallbackArticles();
          setError(null);
        }
      } finally {
        if (active) {
          setLoading(false);
        }
      }
    };

    loadArticles();

    return () => {
      active = false;
    };
  }, []);

  if (loading) {
    return <Spin size="large" tip="Loading articles from the API..." />;
  }

  if (error) {
    return <Alert className="page-card" type="error" showIcon message="Unable to load articles" description={error} />;
  }

  if (!articles.length) {
    return <div>There is no article available now.</div>;
  }

  return (
    <div className="article-grid">
      <Title level={2}>Latest Articles</Title>
      <Row gutter={[16, 16]} justify="space-around">
        {articles.map((article) => (
          <Col xs={24} sm={12} lg={8} key={article.id}>
            <Card
              className="article-card"
              cover={article.image ? <img alt={article.title} src={article.image} style={{ height: 180, objectFit: 'cover' }} /> : null}
              title={article.title}
              extra={<Tag color="blue">#{article.id}</Tag>}
            >
              <Paragraph>{article.body}</Paragraph>
              <Link to={`/a/${article.id}`}>Details</Link>
            </Card>
          </Col>
        ))}
      </Row>
    </div>
  );
};

export default Articles;

import React, { useState } from 'react';

type GoodbyeProps = {
  name?: string;
};

const Goodbye = ({ name = 'everyone' }: GoodbyeProps) => {
  const [txtColor, setTxtColor] = useState('blue');

  const changeColor = () => setTxtColor('red');
  const revertColor = () => setTxtColor('blue');

  return (
    <h1
      onMouseEnter={changeColor}
      onMouseLeave={revertColor}
      style={{ color: txtColor }}
    >
      Goodbye {name}
    </h1>
  );
};

export default Goodbye;

import React from 'react';

type HelloProps = {
  name?: string;
};

const Hello = ({ name }: HelloProps) => {
  const greeting = name ? `Hello ${name}` : 'Hello World';

  return <h1>{greeting}</h1>;
};

export default Hello;

import React from 'react';
import { Card, Typography } from 'antd';
import Articles from './Articles';
import Hello from './Hello';

const { Paragraph, Title } = Typography;

const Home = () => (
